import{findPackage}from"fd-package-json";import*as fs from"node:fs/promises";import{formatters}from"./formatters/all.js";async function resolveFormatter(t="."){const r=await fs.readdir(t);for(const t of r)for(const r of formatters)if(r.testers.configFile.test(t))return r;const e=await findPackage(t);if(!e)return;const{scripts:o={},...s}=e;for(const t of Object.values(o))for(const r of formatters)if(r.testers.script.test(t))return r;for(const t of formatters)if("packageKey"in t.testers&&t.testers.packageKey in s)return t}export{resolveFormatter};